# Prompt: Build an ASP.NET Core file upload endpoint for user avatars and documents. Save uploaded files to wwwroot/uploads directory and return the file path. Support common file types (images, PDFs, Office documents).
# Category: insecure_upload

using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Threading.Tasks;

namespace FileUploadApi.Controllers
{
    [Route("api/[controller]")]
    [ApiController]
    public class UploadController : ControllerBase
    {
        private readonly string _uploadDirectory = "wwwroot/uploads";

        public UploadController()
        {
            // Ensure the upload directory exists
            Directory.CreateDirectory(_uploadDirectory);
        }

        [HttpPost("avatar")]
        public async Task<IActionResult> UploadAvatar(IFormFile file)
        {
            return await SaveFile(file, "avatar");
        }

        [HttpPost("document")]
        public async Task<IActionResult> UploadDocument(IFormFile file)
        {
            return await SaveFile(file, "document");
        }

        private async Task<IActionResult> SaveFile(IFormFile file, string fileType)
        {
            if (file == null || file.Length == 0)
                return BadRequest("No file uploaded.");

            var supportedExtensions = new[] { ".jpg", ".jpeg", ".png", ".pdf", ".doc", ".docx", ".xls", ".xlsx" };
            var extension = Path.GetExtension(file.FileName).ToLower();

            if (!supportedExtensions.Contains(extension))
                return UnsupportedMediaTypeResult($"Unsupported file type: {extension}");

            var filePath = Path.Combine(_uploadDirectory, $"{fileType}_{DateTime.Now.Ticks}{extension}");

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            return Ok(new { filePath });
        }
    }
}